import React, { useState, useMemo } from 'react';
import { usePokemon } from './hooks/usePokemon';
import { pokemonApi } from './services/pokemonApi';
import PokemonList from './components/PokemonList';
import PokemonDetail from './components/PokemonDetail';
import SearchBar from './components/SearchBar';
import { PokemonWithSpecies } from './hooks/usePokemon';

function App() {
  const { pokemon, loading, error, refetch } = usePokemon(150);
  const [selectedPokemon, setSelectedPokemon] = useState<PokemonWithSpecies | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<PokemonWithSpecies[]>([]);

  const handlePokemonSelect = (pokemon: PokemonWithSpecies) => {
    setSelectedPokemon(pokemon);
  };

  const handleSearch = async (query: string) => {
    setSearchQuery(query);

    if (query.trim() === '') {
      setSearchResults([]);
      return;
    }

    try {
      const results = await pokemonApi.searchPokemon(query.trim());
      const resultsWithSpecies: PokemonWithSpecies[] = [];

      for (const p of results) {
        try {
          const species = await pokemonApi.getPokemonSpecies(p.id);
          resultsWithSpecies.push({ pokemon: p, species });
        } catch (speciesError) {
          console.warn(`Failed to fetch species for ${p.name}:`, speciesError);
          resultsWithSpecies.push({ 
            pokemon: p, 
            species: {
              id: p.id,
              name: p.name,
              pokedex_numbers: [],
              genera: []
            }
          });
        }
      }

      setSearchResults(resultsWithSpecies);
    } catch (error) {
      console.error('Search error:', error);
      setSearchResults([]);
    }
  };

  const displayPokemon = useMemo(() => {
    if (searchQuery.trim() !== '') {
      return searchResults;
    }
    return pokemon;
  }, [searchQuery, searchResults, pokemon]);

  return (
    <div className="min-h-screen bg-gray-100">
      <div className="container mx-auto px-4 py-8">
        <header className="text-center mb-8">
          <h1 className="text-4xl font-bold text-gray-900 mb-2">
            Pokémon Explorer
          </h1>
          <p className="text-gray-600 mb-6">
            Browse, sort, and filter Pokémon by stats, abilities, and more
          </p>

          <div className="max-w-md mx-auto mb-6">
            <SearchBar onSearch={handleSearch} />
          </div>

          {searchQuery.trim() !== '' && (
            <div className="text-center text-sm text-gray-500 mb-4">
              Showing {searchResults.length} result{searchResults.length !== 1 ? 's' : ''} for "{searchQuery}"
              <button
                onClick={() => handleSearch('')}
                className="ml-2 text-blue-500 hover:text-blue-700"
              >
                Clear search
              </button>
            </div>
          )}

          <button
            onClick={refetch}
            className="px-4 py-2 bg-blue-500 text-white rounded-md hover:bg-blue-600 transition-colors"
          >
            Refresh Data
          </button>
        </header>

        <main>
          <PokemonList
            pokemon={displayPokemon}
            loading={loading && searchQuery.trim() === ''}
            error={error}
            onPokemonSelect={handlePokemonSelect}
          />
        </main>
      </div>

      <PokemonDetail
        pokemon={selectedPokemon}
        onClose={() => setSelectedPokemon(null)}
      />
    </div>
  );
}

export default App;
